SELECT c.*, u.username, up.avatar as user_avatar, b.title as blog_title FROM comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN user_profile up ON u.id = up.user_id LEFT JOIN blog b ON c.blog_id = b.id
AND c.content LIKE CONCAT('%', #{keyword}, '%')
AND c.status = #{status}
ORDER BY c.created_at DESC LIMIT #{offset}, #{size}

